#include<bits/stdc++.h>
#define int long long
const int N = 1e7 + 7;
using namespace std;
int w[N],v[N],dp[N];
int s,n,d;
signed main(){ 
	cin >> s >> n >> d;
	int mini = 1e9 + 7;
	for(int i = 1; i <= d; i++){
		cin >> w[i] >> v[i];
		mini = min(mini, w[i]);
	}
	while(n--){
		for(int i = 1; i <= s / 1000; i++) dp[i] = 0; 
		for(int i = 1; i <= d; i++){ 
			for(int j = w[i] / 1000; j <= s / 1000; j++)
				dp[j] = max(dp[j],dp[j - w[i] / 1000] + v[i]);
		}
		s += dp[s / 1000];
	}
	cout << s; 
}
